arguments.command:
cd /tmp/symbols

# Get all dynamic symbols sorted by address, use python for proper hex sorting
aarch64-linux-gnu-nm -D --defined-only libmonosgen-2.0.so.sym 2>/dev/null | python3 -c "
import sys

# Parse symbols
symbols = []
for line in sys.stdin:
    parts = line.strip().split()
    if len(parts) >= 3:
        try:
            addr = int(parts[0], 16)
            stype = parts[1]
            name = parts[2]
            symbols.append((addr, stype, name))
        except ValueError:
            pass

symbols.sort(key=lambda x: x[0])

# Find nearest symbol for each PC
pcs = {
    '#01': 0x222098,
    '#02': 0x222234,
    '#03': 0x19bac0,
    '#06': 0x19bc14,
}

for frame, pc in sorted(pcs.items(), key=lambda x: x[1]):
    best = None
    for addr, stype, name in symbols:
        if addr <= pc:
            best = (addr, stype, name)
        else:
            break
    if best:
        offset = pc - best[0]
        print(f'{frame} pc 0x{pc:x} -> {best[2]}+0x{offset:x} (symbol at 0x{best[0]:x})')
    else:
        print(f'{frame} pc 0x{pc:x} -> <no symbol found>')
"

